let cache;
try { cache = JSON.parse($input.item.json.stdout || '{}'); } catch { return []; }
const funnel = cache.funnel || [];
const health = cache.health || {};
const leaks = [];
let maxLeak = 0;
for (let i = 1; i < funnel.length; i++) {
  const prev = funnel[i-1].count || 0;
  const curr = funnel[i].count || 0;
  if (prev === 0) continue;
  const lossPct = (1 - curr/prev) * 100;
  if (lossPct > maxLeak) maxLeak = lossPct;
  leaks.push(`${funnel[i-1].label}→${funnel[i].label}: ${lossPct.toFixed(0)}% leak`);
}
const healthBad = (health.bounceRate > 2) || (health.complaintRate > 0.1);
if (leaks.length === 0 && !healthBad) return [];
const priority = (maxLeak > 95 || healthBad) ? 'P1' : 'P2';
const healthLine = healthBad ? `\n• HEALTH: bounce ${health.bounceRate}% · complaint ${health.complaintRate}%` : '';
return [{ json: {
  priority,
  source: 'funnel-dropout-watch',
  message: `Funnel digest:\n${leaks.map(l => `• ${l}`).join('\n')}${healthLine}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/contacts'
} }];
